import React, { useState } from 'react';
import { NavLink, useLocation, useRouteMatch} from 'react-router-dom';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import './Header.scss';
import { Categories } from '../Categories';

export const Header = ({ query, setQuery, applyQuery, setClick }) => {
  const [menu, setMenu] = useState(true);
  // const [query, setQuery] = useState('');
  // const [appliedQuery, setAppliedQuery] = useState('');
  // const [value, setValue] = useState('');
  // const [categories, setCategories] = useState(false);
  const location = useLocation();
  // console.log(location.pathname);
  // const {pathname}
  const [path, setPath] = useState(lo);
  const match = useRouteMatch('/home');
  const par = useRouteMatch.params;
  // console.log(match, par)
  console.log(path, location.pathname);
  // const location = useLocation();
  const searchParams = new URLSearchParams(location.search);
  // const applyiedQuery = searchParams.get('query') || '';
  console.log(location, searchParams);
  console.log(match);

  return (
    <header className="Header">
      <div className="container-headerNav">
        <form className="Header-Form form">
          <button
            type="button"
            className="button-search"
            onClick={() => setQuery('')}
          />
          <input
            type="text"
            className="form-input"
            value={query}
            onChange={(e) => {
              setQuery(e.target.value);
              applyQuery(e.target.value);
            }}
            placeholder="Search..."
          />
          {query && (
            <button
              type="button"
              className="button-clear"
              onClick={() => {
                setQuery('');
                applyQuery('');
                setClick(false);
              }}
            >
              {}
            </button>
          )}
        </form>
        <div className="container-nav">
          <nav className="Header-Nav Nav">
            <NavLink
              to="/home"
              className="Nav-Link"
              onClick={() => {
                setPath('/home');
                setClick(false);
              }}
            >
              Home
            </NavLink>
            <NavLink
              to="/articles"
              className="Nav-Link"
              onClick={() => {
                setPath('/articles');
                setClick(false);
              }}
            >
              Articles
            </NavLink>
          </nav>
          <div className="container-links">
            <a href="http://insagram.com" className="Header-Instagram link">{}</a>
            <a href="http://twitter.com" className="Header-Twitter link">{}</a>
            <a href="http://linkedin.com" className="Header-LinkedIn link">{}</a>
          </div>
        </div>
      </div>
      <div className={classNames('container', {
        container_menu: menu,
      })}
      >
        <div className={classNames('Header-Logo', {
          logo_visible: !menu,
        })}
        >
          News App
        </div>
        <div className="Header-Menu Menu">
          <ul className={classNames('Menu-List', {
            menu_visible: !menu,
          })}
          >
            <li className="Menu-Item">
              <div className="container-category">
                <NavLink
                  to={`${path}/categories`}
                  // to={location.pathname.includes('categories')
                  //   ? `${location.pathname}${location.search}`
                  //   : `${location.pathname}/categories`}
                  className="Menu-Link"
                  onClick={() => <Categories />}
                >
                  Categories
                </NavLink>
                {location.pathname.includes('categories') && <Categories />}
              </div>
            </li>
            <li className="Menu-Item">
              <NavLink
                 to={`${path}/trending`}
                // to={location.pathname.includes('categories')
                //   ? `${location.pathname
                //     .slice(0, location.pathname
                //       .lastIndexOf('/'))}/trending`
                //   : `${path}/trending`}
                 className="Menu-Link"
              >
                Trending news{/* &#9889; Trending news */}
              </NavLink>
            </li>
          </ul>
          <button
            type="button"
            className={classNames('button-menu', {
              menu_open: menu,
              menu_cross: !menu,
            })}
            onClick={() => setMenu(!menu)}
          />
        </div>
      </div>
    </header>
  );
};

Header.propTypes = {
  query: PropTypes.string.isRequired,
  setQuery: PropTypes.func.isRequired,
  applyQuery: PropTypes.func.isRequired,
  setClick: PropTypes.func.isRequired,
};
